{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMPUcVBqQjs2+OUK3Pex2Nw"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"id":"gLcEEBNPVlNo","executionInfo":{"status":"ok","timestamp":1773122529444,"user_tz":-180,"elapsed":146,"user":{"displayName":"Bassem Amin","userId":"03844483762484690298"}}},"outputs":[],"source":["\"\"\"\n","payment.py\n","-----------\n","Defines the Payment and Invoice classes for processing transactions\n","and generating invoices on the StreamFlix platform.\n","\n","Author: [Your Name]\n","Date: [Submission Date]\n","\"\"\"\n","\n","from datetime import date, datetime\n","\n","\n","class Payment:\n","    \"\"\"\n","    Represents a financial transaction (subscription fee or content purchase).\n","\n","    Attributes:\n","        __payment_id (int): Unique payment identifier.\n","        __user (User): The user making the payment.\n","        __amount (float): Payment amount in USD.\n","        __payment_method (str): Method used (e.g., 'Credit Card', 'PayPal', 'Debit Card').\n","        __payment_date (date): Date of the transaction.\n","        __status (str): Transaction status ('Pending', 'Completed', 'Failed').\n","        __description (str): Description of the payment purpose.\n","    \"\"\"\n","\n","    _id_counter = 5000\n","    VALID_METHODS = ['Credit Card', 'Debit Card', 'PayPal', 'Apple Pay', 'Google Pay']\n","\n","    def __init__(self, user, amount: float, payment_method: str, description: str = \"\"):\n","        \"\"\"\n","        Initialise a new Payment.\n","\n","        Args:\n","            user (User): The paying user.\n","            amount (float): Amount in USD (must be > 0).\n","            payment_method (str): One of the valid payment methods.\n","            description (str): Purpose of the payment.\n","\n","        Raises:\n","            ValueError: If amount <= 0 or payment method is invalid.\n","        \"\"\"\n","        if amount <= 0:\n","            raise ValueError(\"Payment amount must be greater than zero.\")\n","        if payment_method not in Payment.VALID_METHODS:\n","            raise ValueError(f\"Payment method must be one of {Payment.VALID_METHODS}.\")\n","\n","        Payment._id_counter += 1\n","        self.__payment_id = Payment._id_counter\n","        self.__user = user\n","        self.__amount = amount\n","        self.__payment_method = payment_method\n","        self.__payment_date = date.today()\n","        self.__status = \"Pending\"\n","        self.__description = description\n","\n","    # ── Getters ──────────────────────────────────────────────\n","    def get_payment_id(self) -> int:\n","        \"\"\"Return the payment ID.\"\"\"\n","        return self.__payment_id\n","\n","    def get_user(self):\n","        \"\"\"Return the paying user.\"\"\"\n","        return self.__user\n","\n","    def get_amount(self) -> float:\n","        \"\"\"Return the payment amount.\"\"\"\n","        return self.__amount\n","\n","    def get_payment_method(self) -> str:\n","        \"\"\"Return the payment method.\"\"\"\n","        return self.__payment_method\n","\n","    def get_payment_date(self) -> date:\n","        \"\"\"Return the payment date.\"\"\"\n","        return self.__payment_date\n","\n","    def get_status(self) -> str:\n","        \"\"\"Return the payment status.\"\"\"\n","        return self.__status\n","\n","    def get_description(self) -> str:\n","        \"\"\"Return the payment description.\"\"\"\n","        return self.__description\n","\n","    # ── Actions ──────────────────────────────────────────────\n","    def process_payment(self) -> bool:\n","        \"\"\"\n","        Process the payment. Simulates a successful transaction.\n","\n","        Returns:\n","            bool: True if payment was completed successfully.\n","        \"\"\"\n","        # In a real system, this would connect to a payment gateway.\n","        self.__status = \"Completed\"\n","        print(f\"Payment {self.__payment_id} of ${self.__amount:.2f} via \"\n","              f\"{self.__payment_method} completed successfully.\")\n","        return True\n","\n","    def get_payment_details(self) -> dict:\n","        \"\"\"\n","        Return all payment details as a dictionary.\n","\n","        Returns:\n","            dict: Payment attributes.\n","        \"\"\"\n","        return {\n","            'payment_id': self.__payment_id,\n","            'user': self.__user.get_name(),\n","            'amount': self.__amount,\n","            'payment_method': self.__payment_method,\n","            'payment_date': str(self.__payment_date),\n","            'status': self.__status,\n","            'description': self.__description\n","        }\n","\n","    def __str__(self) -> str:\n","        \"\"\"Return a formatted string of the payment.\"\"\"\n","        return (f\"Payment[{self.__payment_id}] ${self.__amount:.2f} | \"\n","                f\"Method: {self.__payment_method} | Status: {self.__status} | \"\n","                f\"User: {self.__user.get_name()} | Date: {self.__payment_date}\")\n","\n","\n","class Invoice:\n","    \"\"\"\n","    Represents an invoice generated after a successful payment.\n","    Uses composition — an invoice cannot exist without a payment.\n","\n","    Attributes:\n","        __invoice_id (int): Unique invoice identifier.\n","        __payment (Payment): The associated payment.\n","        __subtotal (float): Subtotal before tax/discount.\n","        __tax_rate (float): Tax rate as a decimal (e.g., 0.05 for 5%).\n","        __tax_amount (float): Calculated tax amount.\n","        __discount (float): Discount amount in USD.\n","        __total (float): Final payable amount.\n","        __issue_date (date): Date the invoice was generated.\n","        __items (list[str]): Line-item descriptions.\n","    \"\"\"\n","\n","    _id_counter = 6000\n","\n","    def __init__(self, payment: Payment, tax_rate: float = 0.05,\n","                 discount: float = 0.0, items: list = None):\n","        \"\"\"\n","        Generate an invoice from a completed payment.\n","\n","        Args:\n","            payment (Payment): The associated payment (must be Completed).\n","            tax_rate (float): Tax rate (0.0–1.0). Default 5%.\n","            discount (float): Discount in USD. Default 0.\n","            items (list[str]): Invoice line items. Default empty.\n","\n","        Raises:\n","            ValueError: If payment is not completed or parameters are invalid.\n","        \"\"\"\n","        if payment.get_status() != \"Completed\":\n","            raise ValueError(\"Invoice can only be generated for a completed payment.\")\n","        if not (0.0 <= tax_rate <= 1.0):\n","            raise ValueError(\"Tax rate must be between 0.0 and 1.0.\")\n","        if discount < 0:\n","            raise ValueError(\"Discount cannot be negative.\")\n","\n","        Invoice._id_counter += 1\n","        self.__invoice_id = Invoice._id_counter\n","        self.__payment = payment\n","        self.__subtotal = payment.get_amount()\n","        self.__tax_rate = tax_rate\n","        self.__tax_amount = round(self.__subtotal * tax_rate, 2)\n","        self.__discount = discount\n","        self.__total = round(self.__subtotal + self.__tax_amount - self.__discount, 2)\n","        self.__issue_date = date.today()\n","        self.__items = items if items else [payment.get_description()]\n","\n","    # ── Getters ──────────────────────────────────────────────\n","    def get_invoice_id(self) -> int:\n","        \"\"\"Return the invoice ID.\"\"\"\n","        return self.__invoice_id\n","\n","    def get_total(self) -> float:\n","        \"\"\"Return the total payable amount.\"\"\"\n","        return self.__total\n","\n","    def get_invoice_details(self) -> dict:\n","        \"\"\"\n","        Return all invoice details as a dictionary.\n","\n","        Returns:\n","            dict: Invoice attributes.\n","        \"\"\"\n","        return {\n","            'invoice_id': self.__invoice_id,\n","            'payment_id': self.__payment.get_payment_id(),\n","            'user': self.__payment.get_user().get_name(),\n","            'subtotal': self.__subtotal,\n","            'tax_rate': f\"{self.__tax_rate * 100:.1f}%\",\n","            'tax_amount': self.__tax_amount,\n","            'discount': self.__discount,\n","            'total': self.__total,\n","            'issue_date': str(self.__issue_date),\n","            'items': self.__items\n","        }\n","\n","    def generate(self) -> str:\n","        \"\"\"\n","        Generate and return a formatted invoice string.\n","\n","        Returns:\n","            str: The formatted invoice.\n","        \"\"\"\n","        lines = [\n","            \"=\" * 50,\n","            \"          STREAMFLIX INVOICE\",\n","            \"=\" * 50,\n","            f\"  Invoice ID   : {self.__invoice_id}\",\n","            f\"  Payment ID   : {self.__payment.get_payment_id()}\",\n","            f\"  Customer     : {self.__payment.get_user().get_name()}\",\n","            f\"  Date         : {self.__issue_date}\",\n","            \"-\" * 50,\n","            \"  Items:\",\n","        ]\n","        for item in self.__items:\n","            lines.append(f\"    - {item}\")\n","        lines.extend([\n","            \"-\" * 50,\n","            f\"  Subtotal     : ${self.__subtotal:>10.2f}\",\n","            f\"  Tax ({self.__tax_rate * 100:.1f}%)    : ${self.__tax_amount:>10.2f}\",\n","            f\"  Discount     : -${self.__discount:>9.2f}\",\n","            \"-\" * 50,\n","            f\"  TOTAL        : ${self.__total:>10.2f}\",\n","            \"=\" * 50,\n","            f\"  Payment via  : {self.__payment.get_payment_method()}\",\n","            f\"  Status       : {self.__payment.get_status()}\",\n","            \"=\" * 50,\n","        ])\n","        return \"\\n\".join(lines)\n","\n","    def __str__(self) -> str:\n","        \"\"\"Return a brief string representation.\"\"\"\n","        return (f\"Invoice[{self.__invoice_id}] Payment: {self.__payment.get_payment_id()} | \"\n","                f\"Total: ${self.__total:.2f} | Date: {self.__issue_date}\")"]}]}